def _fnmatch_no_slash_crossing(path, pattern):
    path_parts = path.split('/')
    pattern_parts = pattern.split('/')

    if len(path_parts) != len(pattern_parts):
        if pattern.endswith('*'):
            if len(path_parts) < len(pattern_parts):
                return False
        else:
            return False

    for p_part, pt_part in zip(path_parts, pattern_parts):
        if not fnmatch(p_part, pt_part):
            return False

    if pattern.endswith('*') and len(path_parts) > len(pattern_parts):
        pass

    return True

tests = [
    ('A/I.py', 'A/*', True, 'Direct child'),
    ('A/B/C/D.py', 'A/*', False, 'Not direct child'),
    ('E.bin', '**/*.bin', True, 'Root-level .bin'),
    ('F/G.bin', '**/*.bin', True, 'Nested .bin'),
    ('A/B/E.bin', '**/*.bin', True, 'Deep path .bin'),
]

for path, pattern, expected, desc in tests:
    result = _fnmatch_no_slash_crossing(path, pattern)
    status = 'PASS' if result == expected else 'FAIL'
    print(f'{status}: {path} vs {pattern} -> {result} (expected {expected}) - {desc}')
